use crate::engine::{
    FrfProducer, execute, execute_collect_sub_chunked, execute_fold_reduce,
    execute_fold_reduce_sub_chunked, execute_reduce, execute_reduce_sub_chunked,
    execute_sub_chunked,
};

pub trait ParallelIterator: Sized + Send {
    type Item: Send;
    type Producer: FrfProducer<Item = Self::Item>;

    fn into_producer(self) -> Self::Producer;

    fn for_each<F>(self, f: F)
    where
        F: Fn(Self::Item) + Sync + Send,
    {
        execute(self.into_producer(), |iter| iter.for_each(&f));
    }

    fn for_each_init<INIT, InitFn, F>(self, init: InitFn, f: F)
    where
        InitFn: Fn() -> INIT + Sync + Send,
        F: Fn(&mut INIT, Self::Item) + Sync + Send,
    {
        execute(self.into_producer(), |iter| {
            let mut state = init();
            iter.for_each(|item| f(&mut state, item));
        });
    }

    fn reduce<ID, OP>(self, identity: ID, op: OP) -> Self::Item
    where
        ID: Fn() -> Self::Item + Sync + Send,
        OP: Fn(Self::Item, Self::Item) -> Self::Item + Sync + Send,
    {
        execute_reduce(self.into_producer(), identity, op)
    }

    fn map<F, R>(self, f: F) -> Map<Self, F>
    where
        F: Fn(Self::Item) -> R + Sync + Send,
        R: Send,
    {
        Map { base: self, f }
    }

    fn filter<F>(self, f: F) -> Filter<Self, F>
    where
        F: Fn(&Self::Item) -> bool + Sync + Send + Clone,
    {
        Filter { base: self, f }
    }

    fn zip<Z: ParallelIterator>(self, other: Z) -> Zip<Self, Z> {
        Zip { a: self, b: other }
    }

    fn enumerate(self) -> Enumerate<Self> {
        Enumerate { base: self }
    }

    fn collect(self) -> Vec<Self::Item> {
        execute_fold_reduce(
            self.into_producer(),
            Vec::new,
            |mut a, b| {
                a.push(b);
                a
            },
            |mut a, mut b| {
                a.append(&mut b);
                a
            },
        )
    }

    /// Switch to sub-chunked cooperative-yielding execution.
    ///
    /// Splits the work into `max(sub_chunks, K)` coarse-grained chunks and
    /// distributes them across pool workers via a single relaxed atomic
    /// counter. Workers drain the counter until it is exhausted, so slow
    /// chunks do not stall idle threads. Intended for tail-latency-heavy
    /// workloads where the default static K-way split leaves capacity on
    /// the floor.
    ///
    /// Maps to the Fork-Race-Fold Triad (see `open-source/gnosis/FORMAL_LEDGER.md`
    /// §Triad): Fork spawns K workers, Race drains the sub-chunk counter,
    /// Fold combines per-worker partials. Sub-chunking preserves this triad
    /// under skew by keeping the Race phase fluid.
    fn with_sub_chunks(self, sub_chunks: usize) -> SubChunked<Self> {
        SubChunked {
            inner: self,
            sub_chunks,
        }
    }

    /// Sub-chunked execution with a per-thread multiplier.
    ///
    /// Produces `chunks_per_thread * K` total sub-chunks, where `K` is the
    /// detected thread count. Convenience over `with_sub_chunks` when the
    /// right tuning is "each thread sees roughly N chunks" rather than a
    /// fixed absolute count. Grounded choices from the formal ledger:
    ///   * `3` — Triad (Fork/Race/Fold, one race-phase yield per cycle)
    ///   * `12` — Aeon (structural column count, more aggressive balancing)
    fn with_sub_chunks_per_thread(self, chunks_per_thread: usize) -> SubChunked<Self> {
        let k = std::thread::available_parallelism()
            .map(|n| n.get())
            .unwrap_or(1);
        SubChunked {
            inner: self,
            sub_chunks: chunks_per_thread.saturating_mul(k),
        }
    }

    /// Sub-chunked execution with M chosen by a length-aware heuristic.
    ///
    /// Empirically on Apple Silicon (and consistent with the Triad/Aeon
    /// ratios in `FORMAL_LEDGER.md`), the sweet-spot sub-chunk count
    /// scales with workload length:
    ///   * `L ≤ 1K`:   `M = K*3` (Triad minimum, tiny workloads need
    ///     little balancing since they finish fast)
    ///   * `1K ≤ L < 64K`: `M ≈ L/64` (balancing granularity tracks skew)
    ///   * `64K ≤ L ≤ 1M`: `M ≈ L/128` (coarser chunks let the
    ///     runtime handoff's mini-batch stealing activate)
    ///   * `L ≥ 1M`:   capped at `M = K*2048` (beyond here, atomic
    ///     contention on the chunk counter outweighs finer balancing)
    ///
    /// Matches or beats hand-tuned `with_sub_chunks(...)` across the
    /// whole 1K-1M range without requiring the caller to know their
    /// workload size class.
    fn with_sub_chunks_auto(self) -> SubChunked<Self> {
        SubChunked {
            inner: self,
            sub_chunks: SUB_CHUNKS_AUTO,
        }
    }
}

/// Sentinel in `SubChunked::sub_chunks` indicating the length-aware heuristic
/// should pick `M` at execute time from `producer.len()`.
const SUB_CHUNKS_AUTO: usize = usize::MAX;

fn auto_sub_chunks(producer_len: usize) -> usize {
    let k = std::thread::available_parallelism()
        .map(|n| n.get())
        .unwrap_or(1);
    let divisor = if producer_len >= 64 * 1024 { 128 } else { 64 };
    let guess = (producer_len / divisor).max(k * 3);
    guess.min(k * 2048)
}

pub struct SubChunked<I> {
    inner: I,
    sub_chunks: usize,
}

impl<I: ParallelIterator> SubChunked<I> {
    pub fn for_each<F>(self, f: F)
    where
        F: Fn(I::Item) + Sync + Send,
    {
        let producer = self.inner.into_producer();
        let m = if self.sub_chunks == SUB_CHUNKS_AUTO {
            auto_sub_chunks(producer.len())
        } else {
            self.sub_chunks
        };
        execute_sub_chunked(producer, m, |iter| iter.for_each(&f));
    }

    pub fn for_each_init<INIT, InitFn, F>(self, init: InitFn, f: F)
    where
        InitFn: Fn() -> INIT + Sync + Send,
        F: Fn(&mut INIT, I::Item) + Sync + Send,
    {
        let producer = self.inner.into_producer();
        let m = if self.sub_chunks == SUB_CHUNKS_AUTO {
            auto_sub_chunks(producer.len())
        } else {
            self.sub_chunks
        };
        execute_sub_chunked(producer, m, |iter| {
            let mut state = init();
            iter.for_each(|item| f(&mut state, item));
        });
    }

    pub fn reduce<ID, OP>(self, identity: ID, op: OP) -> I::Item
    where
        ID: Fn() -> I::Item + Sync + Send,
        OP: Fn(I::Item, I::Item) -> I::Item + Sync + Send,
    {
        let producer = self.inner.into_producer();
        let m = if self.sub_chunks == SUB_CHUNKS_AUTO {
            auto_sub_chunks(producer.len())
        } else {
            self.sub_chunks
        };
        execute_reduce_sub_chunked(producer, m, identity, op)
    }

    /// Collect into a `Vec`, preserving input order.
    ///
    /// Sub-chunks are processed out of order by workers, but each chunk's
    /// output is stored in its input-index slot and the slots are flattened
    /// in order at the end. Matches the order semantics of the static
    /// `ParallelIterator::collect`.
    pub fn collect(self) -> Vec<I::Item> {
        let producer = self.inner.into_producer();
        let m = if self.sub_chunks == SUB_CHUNKS_AUTO {
            auto_sub_chunks(producer.len())
        } else {
            self.sub_chunks
        };
        execute_collect_sub_chunked(producer, m)
    }

    /// Fold each sub-chunk into `B` then combine partials with `reduce`.
    ///
    /// Worker-local accumulation — ordering of the final `reduce` is not
    /// guaranteed, so `reduce` must be associative (and typically commutative).
    /// Use `collect` if you need input order.
    pub fn fold_reduce<B, INIT, FOLD, REDUCE>(self, init: INIT, fold: FOLD, reduce: REDUCE) -> B
    where
        B: Send,
        INIT: Fn() -> B + Sync + Send,
        FOLD: Fn(B, I::Item) -> B + Sync + Send,
        REDUCE: Fn(B, B) -> B + Sync + Send,
    {
        let producer = self.inner.into_producer();
        let m = if self.sub_chunks == SUB_CHUNKS_AUTO {
            auto_sub_chunks(producer.len())
        } else {
            self.sub_chunks
        };
        execute_fold_reduce_sub_chunked(producer, m, init, fold, reduce)
    }
}

pub struct Map<I, F> {
    base: I,
    f: F,
}

pub struct MapProducer<P, F> {
    base: P,
    f: F,
}

impl<P: FrfProducer, F, R> FrfProducer for MapProducer<P, F>
where
    F: Fn(P::Item) -> R + Sync + Send + Clone,
    R: Send,
{
    type Item = R;
    type Iter = std::iter::Map<P::Iter, F>;

    fn len(&self) -> usize {
        self.base.len()
    }

    fn split_at(self, index: usize) -> (Self, Self) {
        let (left, right) = self.base.split_at(index);
        (
            MapProducer {
                base: left,
                f: self.f.clone(),
            },
            MapProducer {
                base: right,
                f: self.f,
            },
        )
    }

    fn into_iter(self) -> Self::Iter {
        self.base.into_iter().map(self.f)
    }

    fn align_chunk(&self, chunk: usize) -> usize {
        self.base.align_chunk(chunk)
    }
}

impl<I: ParallelIterator, F, R> ParallelIterator for Map<I, F>
where
    F: Fn(I::Item) -> R + Sync + Send + Clone,
    R: Send,
{
    type Item = R;
    type Producer = MapProducer<I::Producer, F>;

    fn into_producer(self) -> Self::Producer {
        MapProducer {
            base: self.base.into_producer(),
            f: self.f,
        }
    }
}

pub struct Filter<I, F> {
    base: I,
    f: F,
}

pub struct FilterProducer<P, F> {
    base: P,
    f: F,
}

impl<P: FrfProducer, F> FrfProducer for FilterProducer<P, F>
where
    F: Fn(&P::Item) -> bool + Sync + Send + Clone,
{
    type Item = P::Item;
    type Iter = std::iter::Filter<P::Iter, F>;

    fn len(&self) -> usize {
        self.base.len()
    }

    fn split_at(self, index: usize) -> (Self, Self) {
        let (left, right) = self.base.split_at(index);
        (
            FilterProducer {
                base: left,
                f: self.f.clone(),
            },
            FilterProducer {
                base: right,
                f: self.f,
            },
        )
    }

    fn into_iter(self) -> Self::Iter {
        self.base.into_iter().filter(self.f)
    }

    fn align_chunk(&self, chunk: usize) -> usize {
        self.base.align_chunk(chunk)
    }
}

impl<I: ParallelIterator, F> ParallelIterator for Filter<I, F>
where
    F: Fn(&I::Item) -> bool + Sync + Send + Clone,
{
    type Item = I::Item;
    type Producer = FilterProducer<I::Producer, F>;

    fn into_producer(self) -> Self::Producer {
        FilterProducer {
            base: self.base.into_producer(),
            f: self.f,
        }
    }
}

pub struct Zip<A, B> {
    a: A,
    b: B,
}

pub struct ZipProducer<A, B> {
    a: A,
    b: B,
}

impl<A: FrfProducer, B: FrfProducer> FrfProducer for ZipProducer<A, B> {
    type Item = (A::Item, B::Item);
    type Iter = std::iter::Zip<A::Iter, B::Iter>;

    fn len(&self) -> usize {
        std::cmp::min(self.a.len(), self.b.len())
    }

    fn split_at(self, index: usize) -> (Self, Self) {
        let (a_l, a_r) = self.a.split_at(index);
        let (b_l, b_r) = self.b.split_at(index);
        (
            ZipProducer { a: a_l, b: b_l },
            ZipProducer { a: a_r, b: b_r },
        )
    }

    fn into_iter(self) -> Self::Iter {
        self.a.into_iter().zip(self.b.into_iter())
    }

    fn align_chunk(&self, chunk: usize) -> usize {
        // Use the maximum alignment requirement of the two zipped producers
        let a_align = self.a.align_chunk(chunk);
        let b_align = self.b.align_chunk(chunk);
        std::cmp::max(a_align, b_align)
    }
}

impl<A: ParallelIterator, B: ParallelIterator> ParallelIterator for Zip<A, B> {
    type Item = (A::Item, B::Item);
    type Producer = ZipProducer<A::Producer, B::Producer>;

    fn into_producer(self) -> Self::Producer {
        ZipProducer {
            a: self.a.into_producer(),
            b: self.b.into_producer(),
        }
    }
}

pub struct Enumerate<I> {
    base: I,
}

pub struct EnumerateProducer<P> {
    base: P,
    offset: usize,
}

impl<P: FrfProducer> FrfProducer for EnumerateProducer<P> {
    type Item = (usize, P::Item);
    type Iter = std::iter::Zip<std::ops::Range<usize>, P::Iter>;

    fn len(&self) -> usize {
        self.base.len()
    }

    fn split_at(self, index: usize) -> (Self, Self) {
        let (left, right) = self.base.split_at(index);
        (
            EnumerateProducer {
                base: left,
                offset: self.offset,
            },
            EnumerateProducer {
                base: right,
                offset: self.offset + index,
            },
        )
    }

    fn into_iter(self) -> Self::Iter {
        (self.offset..self.offset + self.len()).zip(self.base.into_iter())
    }

    fn align_chunk(&self, chunk: usize) -> usize {
        self.base.align_chunk(chunk)
    }
}

impl<I: ParallelIterator> ParallelIterator for Enumerate<I> {
    type Item = (usize, I::Item);
    type Producer = EnumerateProducer<I::Producer>;

    fn into_producer(self) -> Self::Producer {
        EnumerateProducer {
            base: self.base.into_producer(),
            offset: 0,
        }
    }
}

#[cfg(all(test, not(target_arch = "wasm32")))]
mod tests {
    use crate::prelude::*;

    #[test]
    fn sub_chunked_for_each_mut_covers_every_element() {
        let mut data = vec![0u64; 10_000];
        data.par_iter_mut()
            .with_sub_chunks(64)
            .for_each(|x| *x += 1);
        assert!(data.iter().all(|&v| v == 1));
    }

    #[test]
    fn sub_chunked_reduce_matches_sequential_sum() {
        let expected: usize = (0..10_000usize).sum();
        let got = (0..10_000usize)
            .into_par_iter()
            .with_sub_chunks(64)
            .reduce(|| 0, |a, b| a + b);
        assert_eq!(got, expected);
    }

    #[test]
    fn sub_chunked_collect_preserves_length() {
        let data: Vec<u64> = (0..10_000u64).collect();
        let out: Vec<&u64> = data.par_iter().with_sub_chunks(64).collect();
        assert_eq!(out.len(), data.len());
        let sum: u64 = out.iter().copied().copied().sum();
        assert_eq!(sum, data.iter().sum::<u64>());
    }

    #[test]
    fn sub_chunked_collect_preserves_input_order() {
        // Critical property: even though workers drain chunks in
        // completion order, the output vec must reflect the original
        // input sequence — matching the static collect semantics.
        let data: Vec<usize> = (0..10_000usize).collect();
        let out: Vec<&usize> = data.par_iter().with_sub_chunks(64).collect();
        for (i, &v) in out.iter().enumerate() {
            assert_eq!(*v, i, "order broken at index {}", i);
        }
    }

    #[test]
    fn sub_chunked_fold_reduce_sums_correctly() {
        let expected: usize = (0..10_000usize).sum();
        let got = (0..10_000usize)
            .into_par_iter()
            .with_sub_chunks(64)
            .fold_reduce(|| 0usize, |acc, x| acc + x, |a, b| a + b);
        assert_eq!(got, expected);
    }

    #[test]
    fn sub_chunks_below_k_still_uses_k() {
        let mut data = vec![0u64; 1_024];
        data.par_iter_mut().with_sub_chunks(1).for_each(|x| *x += 7);
        assert!(data.iter().all(|&v| v == 7));
    }

    #[test]
    fn sub_chunks_auto_produces_correct_output_across_sizes() {
        // Auto heuristic picks M per size class. Verify correctness
        // (not speed) at each characteristic size — tiny, medium, large.
        for n in [128usize, 10_000, 200_000] {
            let mut data = vec![0u64; n];
            data.par_iter_mut()
                .with_sub_chunks_auto()
                .for_each(|x| *x += 7);
            assert!(
                data.iter().all(|&v| v == 7),
                "auto heuristic missed items at n={}",
                n
            );
        }
    }

    #[test]
    fn sub_chunks_auto_uses_stealable_chunks_for_large_bursts() {
        let m = super::auto_sub_chunks(100_000);

        assert!(m > 0);
        assert!(100_000usize.div_ceil(m) >= 96);
    }

    #[test]
    fn sub_chunks_auto_keeps_one_million_stealable_by_default() {
        let m = super::auto_sub_chunks(1_000_000);

        assert!(m > 0);
        assert!(1_000_000usize.div_ceil(m) >= 96);
    }

    #[test]
    fn sub_chunks_auto_collect_preserves_order() {
        let data: Vec<usize> = (0..50_000usize).collect();
        let out: Vec<&usize> = data.par_iter().with_sub_chunks_auto().collect();
        for (i, &v) in out.iter().enumerate() {
            assert_eq!(*v, i, "auto collect broke order at {}", i);
        }
    }

    #[test]
    fn sub_chunked_tail_stragglers_drain() {
        // Unbalanced workload: last few chunks do 100x more work.
        // Verifies cooperative yielding — no worker is stuck waiting
        // on a single static straggler.
        let n = 4_096usize;
        let mut data = vec![0u64; n];
        data.par_iter_mut()
            .enumerate()
            .with_sub_chunks(64)
            .for_each(|(i, x)| {
                let iters = if i >= n - 128 { 1_000 } else { 10 };
                let mut acc: u64 = 0;
                for j in 0..iters {
                    acc = acc.wrapping_add(j as u64);
                }
                *x = acc;
            });
        assert!(data.iter().all(|&v| v > 0));
    }
}
